// ========================================
// WF2 v4 - VALIDATE & EXTRACT FORM DATA
// NO HARDCODE - FLEXIBLE PARSING
// ========================================

const input = $input.first().json;

console.log('[WF2 v4] ==========================================');
console.log('[WF2 v4] RAW INPUT STRUCTURE:');
console.log('[WF2 v4] Keys:', Object.keys(input));

// Debug: Log first level
if (input.body) {
  console.log('[WF2 v4] input.body keys:', Object.keys(input.body));
  if (input.body.body) {
    console.log('[WF2 v4] input.body.body keys:', Object.keys(input.body.body));
  }
}

// ==========================================
// FLEXIBLE PARSING - Tìm data ở nhiều cấp
// ==========================================

let formData = null;
let parseSource = 'unknown';

// Thứ tự ưu tiên parse:
// 1. FLAT structure (v4 Apps Script): input.body.clarificationId
// 2. Nested 1 level: input.body.data.clarificationId
// 3. Nested 2 levels: input.body.body.data.clarificationId
// 4. Direct: input.clarificationId

if (input.body?.clarificationId) {
  // FLAT structure từ Apps Script v4
  formData = input.body;
  parseSource = 'input.body (FLAT)';
  console.log('[WF2 v4] ✅ Found FLAT structure in input.body');

} else if (input.body?.data?.clarificationId) {
  // Nested 1 level
  formData = input.body.data;
  parseSource = 'input.body.data';
  console.log('[WF2 v4] ✅ Found nested structure in input.body.data');

} else if (input.body?.body?.data?.clarificationId) {
  // Nested 2 levels (double wrapped)
  formData = input.body.body.data;
  parseSource = 'input.body.body.data';
  console.log('[WF2 v4] ✅ Found double-nested structure');

} else if (input.body?.body?.clarificationId) {
  // Nested body without data wrapper
  formData = input.body.body;
  parseSource = 'input.body.body';
  console.log('[WF2 v4] ✅ Found nested body structure');

} else if (input.clarificationId) {
  // Direct at root
  formData = input;
  parseSource = 'input (root)';
  console.log('[WF2 v4] ✅ Found direct structure at root');

} else if (input.data?.clarificationId) {
  // data at root level
  formData = input.data;
  parseSource = 'input.data';
  console.log('[WF2 v4] ✅ Found data at root level');

} else {
  // Fallback: try to find clarificationId anywhere
  console.log('[WF2 v4] ⚠️ Standard structures not found, searching...');

  // Deep search for clarificationId
  const searchForField = (obj, field, path = '') => {
    if (!obj || typeof obj !== 'object') return null;
    if (obj[field]) return { data: obj, path: path };
    for (const key of Object.keys(obj)) {
      const result = searchForField(obj[key], field, path + '.' + key);
      if (result) return result;
    }
    return null;
  };

  const found = searchForField(input, 'clarificationId');
  if (found) {
    formData = found.data;
    parseSource = 'deep search: ' + found.path;
    console.log('[WF2 v4] ✅ Found via deep search at:', found.path);
  }
}

// ==========================================
// EXTRACT META INFO
// ==========================================

const getMeta = (key) => {
  return input[key] || input.body?.[key] || input.body?.body?.[key] || '';
};

const meta = {
  formResponseId: getMeta('formResponseId'),
  timestamp: getMeta('timestamp') || new Date().toISOString(),
  respondentEmail: getMeta('respondentEmail') || 'anonymous',
  editResponseUrl: getMeta('editResponseUrl')
};

// ==========================================
// EXTRACT FORM FIELDS
// ==========================================

if (!formData) {
  console.log('[WF2 v4] ❌ CRITICAL: Could not find form data!');
  console.log('[WF2 v4] Full input:', JSON.stringify(input, null, 2).substring(0, 2000));

  return {
    json: {
      ...meta,
      isValid: false,
      isTest: false,
      parseError: true,
      parseSource: 'FAILED',
      errors: ['Không thể parse form data - cấu trúc payload không hợp lệ']
    }
  };
}

console.log('[WF2 v4] Parse source:', parseSource);
console.log('[WF2 v4] formData keys:', Object.keys(formData));

// Extract với fallback
const clarificationId = formData.clarificationId || '';
const nguonChiDao = formData.nguonChiDao || '';
const ngayNhanChiDao = formData.ngayNhanChiDao || '';
const noiDungGoc = formData.noiDungGoc || '';
const dauMoiT1 = formData.dauMoiT1 || '';
const t2NhiemVu = formData.t2NhiemVu || '';
const t3ChiTieu = formData.t3ChiTieu || '';
const t4ThoiHan = formData.t4ThoiHan || '';
const ghiChu = formData.ghiChu || '';
const xacNhan = formData.xacNhan === true || formData.xacNhan === 'true' || formData.xacNhan === 1;

console.log('[WF2 v4] Extracted fields:');
console.log('  clarificationId:', clarificationId);
console.log('  nguonChiDao:', nguonChiDao);
console.log('  dauMoiT1:', dauMoiT1);
console.log('  t2NhiemVu:', t2NhiemVu ? t2NhiemVu.substring(0, 50) + '...' : '(empty)');
console.log('  t3ChiTieu:', t3ChiTieu ? t3ChiTieu.substring(0, 50) + '...' : '(empty)');
console.log('  t4ThoiHan:', t4ThoiHan);
console.log('  xacNhan:', xacNhan);

// ==========================================
// SKIP TEST PAYLOADS
// ==========================================

const isTest = formData._isTest === true || 
               clarificationId.startsWith('TEST-') || 
               clarificationId.includes('test');

if (isTest) {
  console.log('[WF2 v4] 🧪 TEST payload detected - skipping');
  return {
    json: {
      isTest: true,
      isValid: false,
      skipReason: 'Test payload',
      parseSource
    }
  };
}

// ==========================================
// VALIDATION
// ==========================================

const errors = [];
if (!clarificationId) errors.push('Thiếu Mã Clarification');
if (!t2NhiemVu) errors.push('Thiếu T2 - Nhiệm vụ');
if (!t3ChiTieu) errors.push('Thiếu T3 - Chỉ tiêu');
if (!t4ThoiHan) errors.push('Thiếu T4 - Thời hạn');
if (!xacNhan) errors.push('Chưa xác nhận nhận chỉ đạo');

const isValid = errors.length === 0;
const has4T = Boolean(dauMoiT1 && t2NhiemVu && t3ChiTieu && t4ThoiHan);

console.log('[WF2 v4] Validation: isValid=' + isValid + ', has4T=' + has4T);
if (!isValid) console.log('[WF2 v4] Errors:', errors.join(', '));

// ==========================================
// OUTPUT
// ==========================================

return {
  json: {
    // Meta
    ...meta,
    parseSource,

    // Form data
    clarificationId,
    nguonChiDao,
    ngayNhanChiDao,
    noiDungGoc,
    dauMoiT1,
    t2NhiemVu,
    t3ChiTieu,
    t4ThoiHan,
    ghiChu,
    xacNhan,

    // Validation
    isValid,
    isTest: false,
    has4T,
    errors,

    // For Task creation
    taskTitle: (dauMoiT1 ? dauMoiT1 + ': ' : '') + (noiDungGoc || 'Untitled').substring(0, 80),
    today: new Date().toISOString().split('T')[0]
  }
};

